from flask import request, jsonify
import requests  # Only for testing purpose


def authorize(user):
    try:
        user = requests.get(f"http://localhost:5001/users?user={user}").json()

        return {"status": True}, 200

    except KeyError as e:
        print("Incorrect login data")
        return {"status": False, "msg": str(e)}, 401


def main():
    try:
        user = request.args['username']

        return authorize(user)

    except (KeyError, TypeError):
        msg = {
            'msg': 'Incorrect login',
            'status': False
        }

        print(msg["msg"])

        return jsonify(msg), 401


if __name__ == "__main__":
    main()